INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7f5879d7-05e0-4c80-b415-da55cd61db6d',
  '00000000-0000-0000-0000-000000000001',
  $escape$gRPC — Connection Lifecycle, Keepalive, Reconnection, and Streaming Rooms$escape$,
  $escape$gRPC channels run over HTTP/2, not WebSockets — but they solve the same lifecycle problems with sharper primitives. A channel cycles through five states: IDLE, CONNECTING, READY, TRANSIENT_FAILURE, and SHUTDOWN. Use `conn.GetState()` to read current state and `conn.WaitForStateChange(ctx, state)` to block until a transition occurs.

Heartbeats map directly to HTTP/2 PING frames via `keepalive.ClientParameters`. Set `Time` (ping interval), `Timeout` (ack deadline), and `PermitWithoutStream: true` to keep idle channels alive — this replaces WebSocket ping/pong entirely at the transport layer.

Reconnection is automatic with exponential backoff, but is tunable. Pass a service config JSON to `grpc.WithDefaultServiceConfig` to define per-method retry policies with `maxAttempts`, `initialBackoff`, and retryable status codes. Call `grpc.WaitForReady(true)` on individual RPCs to queue them during TRANSIENT_FAILURE instead of returning immediately.

"Rooms" have no native primitive — model them as bidirectional streaming RPCs. Each client holds an open `stream.Send`/`stream.Recv` goroutine pair; the server registers each stream handle in a `sync.Map` keyed by room ID. A fan-out goroutine per stream dispatches inbound messages to all members. More explicit than socket.io, but avoids a broker entirely at small scale.$escape$,
  $escape$kacp := keepalive.ClientParameters{
    Time:                10 * time.Second,
    Timeout:             3 * time.Second,
    PermitWithoutStream: true,
}
kasp := keepalive.ServerParameters{
    MaxConnectionIdle: 15 * time.Second,
    Time:              5 * time.Second,
    Timeout:           1 * time.Second,
}
client, _ := grpc.NewClient("host:50051", grpc.WithKeepaliveParams(kacp))
server := grpc.NewServer(
    grpc.KeepaliveParams(kasp),
    grpc.KeepaliveEnforcementPolicy(keepalive.EnforcementPolicy{
        MinTime: 5 * time.Second, PermitWithoutStream: true,
    }),
)$escape$,
  $escape$go$escape$,
