INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '631367ef-ca05-40a0-a51d-c86c72ce0873',
  '00000000-0000-0000-0000-000000000001',
  $escape$gRPC + grpc-gateway — REST Resource Naming, Verbs, and Status Code Mapping$escape$,
  $escape$When exposing gRPC services over HTTP via grpc-gateway, REST conventions are enforced through `google.api.http` proto annotations. Resource naming follows the collection/resource pattern — `/v1/users/{user_id}`, never `/v1/getUser`. Verb semantics map directly to RPC intent: `Get*` → `GET` (idempotent, cacheable), `Create*` → `POST`, `Update*` → `PUT`/`PATCH`, `Delete*` → `DELETE`.

Status code translation is automatic: gRPC `NOT_FOUND` → 404, `ALREADY_EXISTS` → 409, `INVALID_ARGUMENT` → 400, `UNAUTHENTICATED` → 401, `PERMISSION_DENIED` → 403. The defaults cover most cases, but override them via a custom `WithErrorHandler` on `runtime.ServeMux`.

Idempotency is implicit in your verb mapping. `GET` and `PUT` are safe to retry — grpc-gateway's generated OpenAPI spec propagates this, so generated clients apply correct retry logic automatically. For `POST` creates, if you need `201 Created` instead of the default `200 OK`, inject a header interceptor to call `w.WriteHeader(http.StatusCreated)` before the response flushes.

The `.proto` file becomes the single source of truth for both your gRPC interface and REST surface — no duplication, no drift.$escape$,
  $escape$// Custom error handler overriding grpc-gateway's default status mapping
mux := runtime.NewServeMux(
    runtime.WithErrorHandler(func(ctx context.Context, mux *runtime.ServeMux,
        m runtime.Marshaler, w http.ResponseWriter, r *http.Request, err error) {
        s := status.Convert(err)
        switch s.Code() {
        case codes.NotFound:
            w.WriteHeader(http.StatusNotFound) // 404
        case codes.AlreadyExists:
            w.WriteHeader(http.StatusConflict) // 409
        case codes.InvalidArgument:
            w.WriteHeader(http.StatusBadRequest) // 400
        default:
            runtime.DefaultHTTPErrorHandler(ctx, mux, m, w, r, err)
        }
    }),
)$escape$,
  $escape$go$escape$,
