INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a151d997-870c-42ca-a014-81c22443afd7',
  '00000000-0000-0000-0000-000000000001',
  $escape$gRPC Authentication — JWT, API Keys, mTLS, and OAuth2 via Metadata and Channel Credentials$escape$,
  $escape$gRPC has two distinct auth layers: channel credentials (transport-level) and call credentials (per-RPC). Conflating them causes subtle bugs.

For JWT and API keys, attach them as metadata entries on each call. On the server, intercept via `ServerInterceptor` and read `Metadata` from the call context — `context.metadata.get('authorization')` in Node or `metadata.get('authorization')` in Go. Never store secrets in gRPC service definitions.

For OAuth2, wrap a `CallCredentials` object around a token-refresh callback. In Go, use `credentials.NewPerRPCCredentials(oauth.NewOauthAccess(token))`. The runtime calls the callback before every RPC, keeping tokens fresh without manual management.

For mTLS, configure `TransportCredentials` at channel construction time with both root CA and client certificate. This authenticates the channel itself, not individual RPCs — combining mTLS with per-call JWT gives you defense-in-depth. On the server, extract the verified peer certificate from `credentials.AuthInfo` to make authorization decisions without trusting client-supplied headers.$escape$,
  $escape$import (
    "google.golang.org/grpc"
    "google.golang.org/grpc/credentials"
    "google.golang.org/grpc/credentials/oauth"
    "golang.org/x/oauth2"
)

token := &oauth2.Token{AccessToken: os.Getenv("API_TOKEN")}

tlsCreds, _ := credentials.NewClientTLSFromFile("ca.pem", "")
perRPCCreds := oauth.NewOauthAccess(token)

conn, _ := grpc.NewClient(
    "api.example.com:443",
    grpc.WithTransportCredentials(tlsCreds),
    grpc.WithPerRPCCredentials(perRPCCreds),
)$escape$,
  $escape$go$escape$,
