INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'acd71b5a-5077-490c-a099-79d10c2dfc45',
  '00000000-0000-0000-0000-000000000001',
  $escape$gRPC — Proto-First Is Your OpenAPI: Clients, Docs, and the buf Workflow$escape$,
  $escape$gRPC is inherently spec-first — your `.proto` file is the contract, not an afterthought. Unlike REST where you debate YAML-first vs annotation-driven code, in gRPC the IDL drives everything downstream. Use `protoc` with language plugins (`protoc-gen-go`, `protoc-gen-grpc-java`) to emit type-safe clients. For OpenAPI documentation, annotate your proto with `google.api.http` options and run `protoc-gen-openapiv2` (from grpc-gateway) to emit a Swagger/OpenAPI 3 spec your REST consumers can use without touching gRPC. The modern approach is `buf generate` with a `buf.gen.yaml` that chains plugins in one pass — Go stubs, gRPC interfaces, and OpenAPI spec from a single source. This eliminates code-first drift: docs and clients are always regenerated together. The critical tradeoff: field number changes and renames silently corrupt wire compatibility. Run `buf breaking --against .git#branch=main` in CI to catch breaking changes before they reach clients. Proto-first is strict, but that strictness is exactly what makes multi-language gRPC ecosystems maintainable at scale.$escape$,
  $escape$# buf.gen.yaml chains all codegen in one pass
buf generate --template buf.gen.yaml

# Block merges that break existing clients
buf breaking --against '.git#branch=main'

# Lint proto style (field naming, package conventions)
buf lint

# Outputs after generate:
# gen/go/service/v1/service.pb.go          <- types
# gen/go/service/v1/service_grpc.pb.go    <- client/server stubs
# gen/openapi/service.swagger.json        <- OpenAPI 3 spec$escape$,
  $escape$bash$escape$,
