INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '94b2aff4-23fe-4354-94e2-2cc2fb930ec4',
  '00000000-0000-0000-0000-000000000001',
  $escape$gRPC API Versioning — Proto Packages Beat Metadata Every Time$escape$,
  $escape$gRPC versioning lives in the `.proto` package declaration, not metadata headers. The full method path (`/package.ServiceName/Method`) embeds version directly — `/helloworld.v1.Greeter/SayHello` vs `/helloworld.v2.Greeter/SayHello`. This is gRPC's structural equivalent of URL versioning: each package generates a separate stub, and clients are pinned at compile time.

Metadata-based versioning (`ctx.SetHeader("x-api-version", "2")`) is technically possible but actively harmful — you discard proto's strong typing, break stub isolation, and push version branching into runtime interceptors instead of the type system.

Backward compatibility rules for in-place evolution:
- Never remove or renumber fields — mark them `reserved` with both number and name
- Only add `optional` fields to existing messages
- Add new RPCs rather than changing existing signatures

For breaking changes, create a `v2` package, generate a new `ServiceDesc`, and register both on the same `grpc.Server`. The server routes purely by full service name, so co-hosting is zero-config. Deprecate `v1` via `google.golang.org/grpc/status` metadata after confirming client migration through server-side method call metrics.$escape$,
  $escape$// Register v1 and v2 on a single gRPC server — no config needed
s := grpc.NewServer()
helloworldv1.RegisterGreeterServer(s, &V1Handler{})
helloworldv2.RegisterGreeterServer(s, &V2Handler{})
// Routes: /helloworld.v1.Greeter/SayHello
//         /helloworld.v2.Greeter/SayHello

// In .proto — protect field numbers when deprecating
// message HelloRequest {
//   reserved 2, 3;
//   reserved "legacy_name";
//   string name = 1;
// }
if err := s.Serve(lis); err != nil {
    log.Fatalf("serve: %v", err)
}$escape$,
  $escape$go$escape$,
