INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '56dfdfe9-d4cb-4223-973d-649c7ccb3a0e',
  '00000000-0000-0000-0000-000000000001',
  $escape$gRPC Security — Reflection Exposure, Metadata Injection, and Payload Validation$escape$,
  $escape$gRPC server reflection is the protobuf equivalent of GraphQL introspection — and just as dangerous in production. When enabled, it lets any client enumerate all your service methods, message types, and field names. Disable it unless you're in a dev environment.

Metadata in gRPC (the HTTP/2 header layer) is a common injection vector. Values passed via `grpc.SetHeader` or client metadata are not sanitized by default. If you forward metadata downstream to a database query, log sink, or another service, treat it as untrusted input.

Protobuf doesn't enforce field constraints at the wire level. A `string user_id = 1` accepts a 10 MB payload unless you explicitly cap it. Use `grpc.MaxRecvMsgSize` on the server and validate fields inside a unary interceptor before they reach your handler. CSRF is largely moot for gRPC (non-browser, no cookies by default), but token-based auth via metadata should use short-lived JWTs and validate the `Authorization` key on every interceptor hop — never trust metadata forwarded from an untrusted peer.$escape$,
  $escape$import (
    "google.golang.org/grpc"
    "google.golang.org/grpc/codes"
    "google.golang.org/grpc/metadata"
    "google.golang.org/grpc/status"
    // Do NOT import: "google.golang.org/grpc/reflection" in prod
)

func ValidationInterceptor(ctx context.Context, req any, _ *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (any, error) {
    md, ok := metadata.FromIncomingContext(ctx)
    if !ok {
        return nil, status.Error(codes.InvalidArgument, "missing metadata")
    }
    if vals := md.Get("x-forwarded-for"); len(vals) > 0 {
        return nil, status.Error(codes.PermissionDenied, "untrusted hop header rejected")
    }
    return handler(ctx, req)
}

// Server setup — cap payload, skip reflection registration
grpc.NewServer(
    grpc.MaxRecvMsgSize(1<<20), // 1 MB
    grpc.UnaryInterceptor(ValidationInterceptor),
)$escape$,
  $escape$go$escape$,
