INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ddca0a70-5afb-4fb9-8f89-16e9c8e5a8d4',
  '00000000-0000-0000-0000-000000000001',
  $escape$gRPC Testing — Contract Tests, Mocks, and Integration Tests Done Right$escape$,
  $escape$gRPC's binary Protobuf contract is your testing anchor. Start with contract validation: use `buf lint` and `buf breaking` in CI to catch proto changes that would break consumers before code is generated. For unit tests, avoid spinning up a real server — use `grpc.NewClientConn` with `bufconn` (an in-memory listener from `google.golang.org/grpc/test/bufconn`) to get a real gRPC connection without networking overhead. This lets interceptors, metadata, and status codes behave identically to production. For mocking, generate mock servers using `mockery` against the generated `*Server` interface rather than hand-rolling stubs — this keeps mocks in sync with your proto. For integration tests, run your actual server with a test database and assert on gRPC status codes (`codes.NotFound`, `codes.InvalidArgument`) using `status.Code(err)`, not raw error strings. Use `grpc_testing.Server` for streaming call simulation. Never test generated proto code itself — trust the toolchain. Focus assertions on your business logic inside the handler, not on Protobuf marshaling.$escape$,
  $escape$lis := bufconn.Listen(1024 * 1024)
s := grpc.NewServer()
pb.RegisterUserServiceServer(s, &UserServiceImpl{})
go s.Serve(lis)

conn, _ := grpc.DialContext(ctx, "bufnet",
    grpc.WithContextDialer(func(ctx context.Context, _ string) (net.Conn, error) {
        return lis.DialContext(ctx)
    }),
    grpc.WithTransportCredentials(insecure.NewCredentials()),
)
client := pb.NewUserServiceClient(conn)

resp, err := client.GetUser(ctx, &pb.GetUserRequest{Id: "123"})
assert.Equal(t, codes.NotFound, status.Code(err))$escape$,
  $escape$go$escape$,
