INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '982e19f9-bcb5-471f-82ec-6c97687219b7',
  '00000000-0000-0000-0000-000000000001',
  $escape$gRPC Filtering & Sorting — AIP-132 Protobuf Field Conventions$escape$,
  $escape$gRPC list RPCs don't use query params — filtering and sorting live as typed fields in your protobuf request message. Google's AIP-132 is the de facto standard: define a `string filter` field accepting CEL expressions (e.g. `status = "ACTIVE" AND created_time > "2024-01-01T00:00:00Z"`) and a `string order_by` field with comma-separated columns and optional ` desc` suffix (e.g. `"created_time desc, name"`). For simple, high-traffic RPCs, skip CEL and use a typed `Filter` message with explicit fields — compile-time safety, zero parser overhead. Always pair with `int32 page_size` and `string page_token` for cursor pagination per AIP-158. Critical server-side rule: validate `order_by` against an allowlist before touching your query layer — never interpolate it into SQL directly. For nested AND/OR logic, model filter trees as a recursive `oneof` in the proto rather than encoding logic into a stringly-typed expression, keeping serialization deterministic and avoiding CEL runtime dependencies in your service.$escape$,
  $escape$func (s *Server) ListUsers(ctx context.Context, req *pb.ListUsersRequest) (*pb.ListUsersResponse, error) {
	alllowed := map[string]bool{"created_time": true, "name": true, "status": true}

	orderBy := "created_time desc"
	if req.OrderBy != "" {
		field := strings.ToLower(strings.TrimSuffix(strings.TrimSuffix(req.OrderBy, " desc"), " asc"))
		if !alllowed[field] {
			return nil, status.Errorf(codes.InvalidArgument, "unsupported order_by field: %q", field)
		}
		orderBy = req.OrderBy
	}

	users, nextToken, err := s.repo.List(ctx, req.Filter, orderBy, req.PageSize, req.PageToken)
	if err != nil {
		return nil, status.Errorf(codes.Internal, "list failed: %v", err)
	}
	return &pb.ListUsersResponse{Users: users, NextPageToken: nextToken}, nil
}$escape$,
  $escape$go$escape$,
